import {
  IsUUID,
  IsString,
  IsOptional,
  IsArray,
  ValidateNested,
  IsNumber,
  IsEnum,
  Min,
} from 'class-validator';
import { Type } from 'class-transformer';
import { ReturnReasonCode } from '../../common/enums/return-reason-code.enum';

export class CreateReturnLineItemDto {
  @IsUUID()
  receiptLineItemId: string;

  @IsNumber()
  @Min(0.01)
  quantityReturned: number;

  @IsEnum(ReturnReasonCode)
  reasonCode: ReturnReasonCode;

  @IsString()
  @IsOptional()
  reasonNotes?: string;
}

export class CreateReturnDto {
  @IsUUID()
  receiptId: string;

  @IsArray()
  @ValidateNested({ each: true })
  @Type(() => CreateReturnLineItemDto)
  lineItems: CreateReturnLineItemDto[];
}

import { IsInt, IsNumber, IsOptional, Min, Max } from 'class-validator';

export class UpdateReturnPolicyDto {
  @IsInt()
  @Min(1)
  @Max(365)
  @IsOptional()
  returnWindowDays?: number;

  @IsNumber()
  @Min(0)
  @Max(100)
  @IsOptional()
  restockingFeeDefault?: number;

  @IsInt()
  @Min(0)
  @IsOptional()
  restockingFeeAfterDaysThreshold?: number;

  @IsNumber()
  @Min(0)
  @Max(100)
  @IsOptional()
  restockingFeeAfterDays?: number;
}

