  }

  if (
    OPERATIONAL_MUTATE_PATTERN.test(url) &&
    ['POST', 'PATCH', 'PUT', 'DELETE'].includes(method)
  ) {
    event.respondWith(mutationWithOfflineQueue(request));
  }
