// ── Activation: remove stale (version-bumped) caches ───────────────────────

self.addEventListener('activate', (event) => {
  const validPrefixes = [
    `greenleaf-kb-${CACHE_VERSION}-`,
    `greenleaf-ops-${CACHE_VERSION}-`,
  ];
