  @Patch(':id/complete')
  @Roles(Role.WAREHOUSE_CLERK, Role.ADMINISTRATOR)
  @HttpCode(HttpStatus.OK)
  complete(@Param('id', ParseUUIDPipe) id: string, @Req() req: Request) {
    const userId = (req.user as { id: string }).id;
    return this.service.complete(id, userId);
  }
}

