  headers: auth(pmToken),
  data: { override: true },   // ← missing overrideReason
});
expect(overrideRes.status()).toBe(403);
```
- REQUIRED FIX for admin: add `overrideReason: 'Emergency greenhouse restock approved by board'`
- REQUIRED FIX for PM: add `overrideReason: 'Urgent restock approved by operations manager'`
- REQUIRED ADDITION: validation path assertion (override=true without overrideReason → 400)

**`repo/server/src/budget/dto/issue-po-override.dto.ts`** — source of contract
```typescript
import { IsBoolean, IsOptional, IsString, MinLength, ValidateIf } from 'class-validator';
export class IssuePoDto {
  @IsBoolean()
  @IsOptional()
  override?: boolean;

  @ValidateIf((o: IssuePoDto) => o.override === true)
  @IsString()
  @MinLength(10, { message: 'Override reason must be at least 10 characters' })
  overrideReason?: string;
}
```

**`repo/server/src/purchase-orders/purchase-orders.controller.ts`** — how override flows
```typescript
issue(@Param('id', ParseUUIDPipe) id, @Body() dto: IssuePoDto, @Req() req) {
  const user = req.user as { id: string; role: string };
  const override: BudgetOverrideContext | undefined =
    dto.override && dto.overrideReason
      ? { authorized: true, reason: dto.overrideReason, role: user.role }
      : undefined;
  return this.service.issue(id, user.id, override);
}
```
Service: if `override.role !== Role.ADMINISTRATOR` → throws `ForbiddenException('Budget cap override requires ADMINISTRATOR role')`

**`repo/server/src/notifications/dto/update-preferences.dto.ts`** — CRITICAL PENDING FIX
- Round 8 confirmed: 0 occurrences of `ValidateNested` — fix NOT persisted
- Current (broken) state:
```typescript
import { IsArray, IsBoolean, IsEnum } from 'class-validator';
import { NotificationType } from '../../common/enums/notification-type.enum';
export class PreferenceItemDto {
  @IsEnum(NotificationType)
  type: NotificationType;
  @IsBoolean()
  isEnabled: boolean;
}
export class UpdatePreferencesDto {
